def fizzbuzz(n):
    # Initialize an empty list to store the result
    result = []

    # Loop through numbers from 1 to n
    for i in range(1, n+1):
        if i % 3 == 0 and i % 5 == 0:
            result.append('FizzBuzz')
        elif i % 3 == 0:
            result.append('Fizz')
        elif i % 5 == 0:
            result.append('Buzz')
        else:
            result.append(str(i))

    return result

